import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

def extract(data):
    result = {}
    for proj in data.get('projects', []):
        name = proj['path'].split('/')[-1]
        for fw in proj.get('frameworks', []):
            for pkg in fw.get('topLevelPackages', []):
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

b = extract(baseline)
a = extract(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []
for k in all_keys:
    proj, fw, pkg = k
    bv = b.get(k, '-')
    av = a.get(k, '-')
    if bv != av:
        if bv == '-':
            changes.append((proj, fw, pkg, bv, av, 'Added'))
        elif av == '-':
            changes.append((proj, fw, pkg, bv, av, 'Removed'))
        else:
            changes.append((proj, fw, pkg, bv, av, 'Aligned to highest version'))
    else:
        unchanged.append((proj, fw, pkg, av))

print('=== CHANGES ===')
if changes:
    print(f'{'Project':<16} {'TFM':<10} {'Package':<45} {'Before':<12} {'After':<12} Status')
    print('-' * 120)
    for c in changes:
        print(f'{c[0]:<16} {c[1]:<10} {c[2]:<45} {c[3]:<12} {c[4]:<12} {c[5]}')
else:
    print('No changes detected.')

print()
print('=== UNCHANGED ===')
print(f'{'Project':<16} {'TFM':<10} {'Package':<45} {'Version':<12}')
print('-' * 90)
for u in unchanged:
    print(f'{u[0]:<16} {u[1]:<10} {u[2]:<45} {u[3]:<12}')
"

